# Day 23: Error Handling: Try, Except, Finally, and Custom Errors
# Error Handling

# Basic try/except
try:
    num = int("abc")
except ValueError as e:
    print(f"Error: {e}")

# Multiple exceptions
def safe_divide(a, b):
    try:
        result = a / b
    except ZeroDivisionError:
        return "Cannot divide by zero"
    except TypeError:
        return "Invalid types"
    else:
        return round(result, 2)
    finally:
        print("  Division attempted")

print(safe_divide(10, 3))
print(safe_divide(10, 0))

# Custom exception
class InvalidAgeError(Exception):
    pass

def set_age(age):
    if age < 0 or age > 150:
        raise InvalidAgeError(f"Age {age} is invalid")
    return age

try:
    set_age(200)
except InvalidAgeError as e:
    print(f"Caught: {e}")
